import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Typography,
  IconButton,
  Stack,
  CircularProgress,
  LinearProgress,
  useTheme,
  Button,
  Switch,
  Chip,
} from '@mui/material';
import {
  OpenInNew as OpenInNewIcon,
  LightMode as LightModeIcon,
  DarkMode as DarkModeIcon,
  Sync as SyncIcon,
} from '@mui/icons-material';
import { getSystemInfo, getSystemStatus, startService, stopService } from '../services/api';
import { getCommonStyles } from '../styles/commonStyles';

const Dashboard = ({ mode, setMode, onDashboardClick = () => {} }) => {
  const theme = useTheme();
  const styles = getCommonStyles(theme);
  const [loading, setLoading] = useState(false);
  const [systemInfo, setSystemInfo] = useState({
    hostname: '',
    platform: '',
    arch: '',
    uptime: 0,
    cpu_usage: 0,
    memory_total: 0,
    memory_used: 0,
    networkUpload: 0,
    networkDownload: 0,
    connections: 0,
    singbox_version: '',
    singbox_uptime: 0,
    mosdns_version: '',
    mosdns_uptime: 0,
  });

  // 定义服务列表
  const services = [
    {
      id: 'singbox',
      name: 'Singbox',
      description: '代理服务',
      active: false,
    },
    {
      id: 'mosdns',
      name: 'Mosdns',
      description: 'DNS服务',
      active: false,
    },
  ];

  // 定义订阅列表
  const [subscriptions, setSubscriptions] = useState([]);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000); // 每5秒更新一次
    return () => clearInterval(interval);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [sysInfo, sysStatus] = await Promise.all([
        getSystemInfo(),
        getSystemStatus(),
      ]);

      // 更新系统信息
      setSystemInfo({
        hostname: sysInfo.hostname || '',
        platform: sysInfo.platform || '',
        arch: sysInfo.arch || '',
        uptime: sysInfo.uptime || 0,
        cpu_usage: sysInfo.cpu_usage || 0,
        memory_total: sysInfo.memory_total || 0,
        memory_used: sysInfo.memory_used || 0,
        networkUpload: sysInfo.network_upload || 0,
        networkDownload: sysInfo.network_download || 0,
        connections: sysInfo.connections || 0,
        singbox_version: sysStatus.services?.singbox_version || '-',
        singbox_uptime: sysStatus.services?.singbox_uptime || 0,
        mosdns_version: sysStatus.services?.mosdns_version || '-',
        mosdns_uptime: sysStatus.services?.mosdns_uptime || 0,
      });

      // 更新服务状态
      services[0].active = sysStatus.services?.singbox || false;
      services[1].active = sysStatus.services?.mosdns || false;

      // 更新订阅信息
      setSubscriptions(sysStatus.subscriptions?.map(sub => ({
        id: sub.id,
        name: sub.name || '未命名订阅',
        nodeCount: sub.node_count || 0,
        lastUpdate: formatDate(sub.last_update),
        expireTime: formatDate(sub.expire_time),
      })) || []);

    } catch (error) {
      console.error('Failed to fetch data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleServiceToggle = async (serviceId) => {
    try {
      setLoading(true);
      const service = services.find(s => s.id === serviceId);
      if (service) {
        if (service.active) {
          await stopService(serviceId);
        } else {
          await startService(serviceId);
        }
      }
      await fetchData();
    } catch (error) {
      console.error(`Failed to toggle ${serviceId}:`, error);
    } finally {
      setLoading(false);
    }
  };

  const formatBytes = (bytes) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(2))} ${sizes[i]}`;
  };

  const formatUptime = (seconds) => {
    const days = Math.floor(seconds / 86400);
    const hours = Math.floor((seconds % 86400) / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    return `${days}天${hours}小时${minutes}分钟`;
  };

  const formatDate = (dateString) => {
    if (!dateString) return '-';
    const date = new Date(dateString);
    return date.toLocaleString('zh-CN', {
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
  };

  const handleUpdateAllSubscriptions = async () => {
    try {
      setLoading(true);
      // TODO: 实现更新所有订阅的 API 调用
      await fetchData();
    } catch (error) {
      console.error('Failed to update all subscriptions:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateSubscription = async (id) => {
    try {
      setLoading(true);
      // TODO: 实现更新单个订阅的 API 调用
      await fetchData();
    } catch (error) {
      console.error(`Failed to update subscription ${id}:`, error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ p: 3 }}>
      <Card sx={styles.headerCard}>
        <CardContent>
          <Typography variant="h5" gutterBottom>
            仪表盘
          </Typography>
        </CardContent>
      </Card>

      <Grid container spacing={3}>
        {/* 系统信息卡片 */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                系统信息
              </Typography>
              <Stack spacing={1}>
                <Typography variant="body2">
                  操作系统：{systemInfo.platform}
                </Typography>
                <Typography variant="body2">
                  架构：{systemInfo.arch}
                </Typography>
                <Typography variant="body2">
                  运行时间：{formatUptime(systemInfo.uptime)}
                </Typography>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* CPU使用率卡片 */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                CPU 使用率
              </Typography>
              <Box sx={{ position: 'relative', display: 'inline-flex', width: '100%', justifyContent: 'center' }}>
                <CircularProgress
                  variant="determinate"
                  value={systemInfo.cpu_usage}
                  size={80}
                  thickness={4}
                  sx={styles.circularProgress}
                />
                <Box
                  sx={{
                    top: 0,
                    left: 0,
                    bottom: 0,
                    right: 0,
                    position: 'absolute',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                  }}
                >
                  <Typography variant="h6">
                    {`${Math.round(systemInfo.cpu_usage)}%`}
                  </Typography>
                </Box>
              </Box>
            </CardContent>
          </Card>
        </Grid>

        {/* 内存使用率卡片 */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                内存使用率
              </Typography>
              <Box sx={{ position: 'relative', display: 'inline-flex', width: '100%', justifyContent: 'center' }}>
                <CircularProgress
                  variant="determinate"
                  value={(systemInfo.memory_used / systemInfo.memory_total) * 100}
                  size={80}
                  thickness={4}
                  sx={styles.circularProgress}
                />
                <Box
                  sx={{
                    top: 0,
                    left: 0,
                    bottom: 0,
                    right: 0,
                    position: 'absolute',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                  }}
                >
                  <Typography variant="h6">
                    {`${Math.round((systemInfo.memory_used / systemInfo.memory_total) * 100)}%`}
                  </Typography>
                </Box>
              </Box>
              <Typography variant="body2" sx={{ mt: 1, textAlign: 'center' }}>
                {`${(systemInfo.memory_used / 1024 / 1024 / 1024).toFixed(1)}GB / ${(systemInfo.memory_total / 1024 / 1024 / 1024).toFixed(1)}GB`}
              </Typography>
            </CardContent>
          </Card>
        </Grid>

        {/* 网络状态卡片 */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                网络状态
              </Typography>
              <Stack spacing={1}>
                <Typography variant="body2">
                  上传：{(systemInfo.networkUpload / 1024).toFixed(2)} KB/s
                </Typography>
                <Typography variant="body2">
                  下载：{(systemInfo.networkDownload / 1024).toFixed(2)} KB/s
                </Typography>
                <Typography variant="body2">
                  连接数：{systemInfo.connections}
                </Typography>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Singbox状态卡片 */}
        <Grid item xs={12} md={6}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack direction="row" justifyContent="space-between" alignItems="center" mb={2}>
                <Typography variant="h6">
                  Singbox 状态
                </Typography>
                <Chip
                  label={services[0].active ? "运行中" : "已停止"}
                  color={services[0].active ? "success" : "error"}
                  sx={styles.chip[services[0].active ? "success" : "error"]}
                />
              </Stack>
              <Stack spacing={1}>
                <Typography variant="body2">
                  版本：{systemInfo.singbox_version}
                </Typography>
                <Typography variant="body2">
                  运行时间：{formatUptime(systemInfo.singbox_uptime)}
                </Typography>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Mosdns状态卡片 */}
        <Grid item xs={12} md={6}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack direction="row" justifyContent="space-between" alignItems="center" mb={2}>
                <Typography variant="h6">
                  Mosdns 状态
                </Typography>
                <Chip
                  label={services[1].active ? "运行中" : "已停止"}
                  color={services[1].active ? "success" : "error"}
                  sx={styles.chip[services[1].active ? "success" : "error"]}
                />
              </Stack>
              <Stack spacing={1}>
                <Typography variant="body2">
                  版本：{systemInfo.mosdns_version}
                </Typography>
                <Typography variant="body2">
                  运行时间：{formatUptime(systemInfo.mosdns_uptime)}
                </Typography>
              </Stack>
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

export default Dashboard;
